3	const PROCESSING_FEE = 5;
4	const FIRST_INSURANCE_SURCHARGE = 0.1;
5	const CURSED_SURCHARGE_RATE = 0.5;
6	const HIGH_ENCHANTMENT_SURCHARGE_RATE = 0.3;
7	const HIGH_ENCHANTMENT_THRESHOLD = 5;
8	
9	const BASE_PREMIUMS: Record<string, number> = {
10	  sword: 100,
11	  amulet: 60,
12	  staff: 80,
13	  potion: 40,
14	  rune: 25,
15	  moonstone: 25,
16	};
17	
18	type Item = { type: string; material?: string; cursed?: boolean; enchantment?: number };
19	type Damage = { itemType: string; amount: number };
20	type Incident = { cause?: string; damages: Damage[] };
21	type Step = {
22	  op: string;
23	  items?: Item[];
24	  policy?: number;
25	  incident?: Incident;
26	};
27	type Customer = { yearsWithMHPCO?: number };
28	type Scenario = { steps: Step[]; customer?: Customer };
29	
30	const INSURANCE_VALUES: Record<string, number> = {
31	  sword: 1000,
32	  amulet: 600,
33	  staff: 800,
34	  potion: 400,
35	  rune: 250,
36	  moonstone: 250,
37	};
38	
39	const DEDUCTIBLE = 100;
40	const CAP_MULTIPLIER = 2;
41	const HIGH_ENCHANTMENT_CLAIM_THRESHOLD = 8;
42	
43	const insuranceValueForType = (type: string): number =>
44	  INSURANCE_VALUES[type] ?? 0;
45	
46	const sumPolicyInsurance = (items: Item[]): number =>
47	  items.reduce((sum, item) => sum + insuranceValueForType(item.type), 0);
48	
49	const findItemInPolicy = (items: Item[], itemType: string): Item => {
50	  const found = items.find((i) => i.type === itemType);
51	  if (!found) throw new Error(`Item type ${itemType} not in policy`);
52	  return found;
53	};
54	
55	const reimbursementForDamage = (item: Item, amount: number): number => {
56	  const enchantment = item.enchantment ?? 0;
57	  const reimbursed =
58	    enchantment >= HIGH_ENCHANTMENT_CLAIM_THRESHOLD ? amount * 0.5 : amount;
59	  return Math.max(0, reimbursed - DEDUCTIBLE);
60	};
61	
62	type ClaimResult = { payout: number; remainingCap: number };
63	
64	const processClaim = (
65	  step: Step,
66	  policySteps: Map<number, Step>,
67	  remainingCaps: Map<number, number>,
68	): ClaimResult => {
69	  const policyIndex = step.policy as number;
70	  const policyStep = policySteps.get(policyIndex);
71	  if (!policyStep || !policyStep.items) {
72	    throw new Error(`Policy at index ${policyIndex} not found`);
73	  }
74	  const damages = step.incident?.damages ?? [];
75	  const totalReimbursement = damages.reduce((sum, damage) => {
76	    const item = findItemInPolicy(policyStep.items!, damage.itemType);
77	    return sum + reimbursementForDamage(item, damage.amount);
78	  }, 0);
79	  const remainingCap = remainingCaps.get(policyIndex) ?? 0;
80	  const payout = Math.floor(Math.min(totalReimbursement, remainingCap));
81	  remainingCaps.set(policyIndex, remainingCap - payout);
82	  return { payout, remainingCap: remainingCap - payout };
83	};
84	
85	const COMPONENT_TYPES = new Set(["rune", "moonstone"]);
86	const BLOCK_SIZE = 3;
87	const BLOCK_BASE_PREMIUM = 60;
88	
89	const basePremiumForType = (type: string): number => BASE_PREMIUMS[type] ?? 0;
90	
91	const itemBasePremium = (item: Item): number => basePremiumForType(item.type);
92	
93	const isComponent = (item: Item): boolean => COMPONENT_TYPES.has(item.type);
94	
95	const countByType = (items: Item[]): Map<string, number> => {
96	  const counts = new Map<string, number>();
97	  for (const item of items) {
98	    counts.set(item.type, (counts.get(item.type) ?? 0) + 1);
99	  }
100	  return counts;
101	};
102	
103	const componentGroupPremium = (type: string, count: number): number =>
104	  count === BLOCK_SIZE ? BLOCK_BASE_PREMIUM : count * basePremiumForType(type);
105	
106	const sumItemBasePremiums = (items: Item[]): number => {
107	  const nonComponents = items.filter((item) => !isComponent(item));
108	  const components = items.filter(isComponent);
109	  const nonComponentsTotal = nonComponents.reduce(
110	    (sum, item) => sum + itemBasePremium(item),
111	    0,
112	  );
113	  const componentsTotal = Array.from(countByType(components)).reduce(
114	    (sum, [type, count]) => sum + componentGroupPremium(type, count),
115	    0,
116	  );
117	  return nonComponentsTotal + componentsTotal;
118	};
119	
120	const isCursed = (item: Item): boolean => item.cursed === true;
121	
122	const isHighlyEnchanted = (item: Item): boolean =>
123	  (item.enchantment ?? 0) >= HIGH_ENCHANTMENT_THRESHOLD;
124	
125	const cursedSurcharge = (item: Item, base: number): number =>
126	  isCursed(item) ? base * CURSED_SURCHARGE_RATE : 0;
127	
128	const highEnchantmentSurcharge = (item: Item, base: number): number =>
129	  isHighlyEnchanted(item) ? base * HIGH_ENCHANTMENT_SURCHARGE_RATE : 0;
130	
131	const itemSurcharge = (item: Item): number => {
132	  const base = itemBasePremium(item);
133	  return cursedSurcharge(item, base) + highEnchantmentSurcharge(item, base);
134	};
135	
136	const sumItemSurcharges = (items: Item[]): number =>
137	  items.reduce((sum, item) => sum + itemSurcharge(item), 0);
138	
139	const LOYALTY_DISCOUNT_RATE = 0.2;
140	const LOYALTY_THRESHOLD_YEARS = 2;
141	
142	const isLongStandingCustomer = (customer: Customer | undefined): boolean =>
143	  (customer?.yearsWithMHPCO ?? 0) >= LOYALTY_THRESHOLD_YEARS;
144	
145	const loyaltyDiscountFor = (customer: Customer | undefined, base: number): number =>
146	  isLongStandingCustomer(customer) ? base * LOYALTY_DISCOUNT_RATE : 0;
147	
148	const FOLLOW_UP_DISCOUNT_RATE = 0.15;
149	
150	const followUpDiscountFor = (isFollowUp: boolean, base: number): number =>
151	  isFollowUp ? base * FOLLOW_UP_DISCOUNT_RATE : 0;
152	
153	const quotePremiumFor = (
154	  step: Step,
155	  customer: Customer | undefined,
156	  isFollowUp: boolean,
157	): number => {
158	  const items = step.items ?? [];
159	  const itemsBase = sumItemBasePremiums(items);
160	  const surcharges =
161	    sumItemSurcharges(items) + itemsBase * FIRST_INSURANCE_SURCHARGE;
162	  const discounts =
163	    loyaltyDiscountFor(customer, itemsBase) +
164	    followUpDiscountFor(isFollowUp, itemsBase);
165	  return Math.ceil(itemsBase + surcharges - discounts + PROCESSING_FEE);
166	};
167	
168	const validateItemTypes = (items: Item[]): void => {
169	  for (const item of items) {
170	    if (!(item.type in BASE_PREMIUMS)) {
171	      throw new Error(`Unknown item type: ${item.type}`);
172	    }
173	  }
174	};
175	
176	export function runScenario(scenario: unknown): { results: any[] } {
177	  const s = scenario as Scenario;
178	  const policySteps = new Map<number, Step>();
179	  const remainingCaps = new Map<number, number>();
180	  const results = s.steps.map((step, index) => {
181	    if (step.op === "claim") {
182	      return processClaim(step, policySteps, remainingCaps);
183	    }
184	    const items = step.items ?? [];
185	    validateItemTypes(items);
186	    policySteps.set(index, step);
187	    remainingCaps.set(index, sumPolicyInsurance(items) * CAP_MULTIPLIER);
188	    return { premium: quotePremiumFor(step, s.customer, index > 0) };
189	  });
190	  return { results };
191	}
